     9→let isConnected = false;
    10→let retryInterval: ReturnType<typeof setInterval> | null = null;
    11→
    12→export function getIsConnected() {
    13→  return isConnected;
    14→}
    15→
    16→async function tryConnect(uri: string): Promise<boolean> {
    17→  try {
    18→    if (mongoose.connection.readyState !== 0) {
    19→      await mongoose.disconnect();
    20→    }
    21→    await mongoose.connect(uri, {
    22→      serverSelectionTimeoutMS: 10000,
    23→      connectTimeoutMS: 10000,
    24→      socketTimeoutMS: 30000,
    25→      bufferCommands: true,
    26→      // ── Connection pool tuned for high concurrency ──
    27→      maxPoolSize: parseInt(process.env.MONGO_POOL_MAX || "50", 10),
    28→      minPoolSize: parseInt(process.env.MONGO_POOL_MIN || "5", 10),
    29→      maxIdleTimeMS: 60_000,
    30→      compressors: ["zstd", "zlib"],
    31→    } as any);
    32→    isConnected = true;
    33→    console.log("Connected to MongoDB successfully");
    34→    return true;
    35→  } catch (err: any) {
    36→    console.error("MongoDB connection attempt failed:", err?.message?.split('\n')[0] || err);
    37→    return false;
    38→  }
    39→}
    40→
    41→function startBackgroundRetry(uri: string) {
    42→  if (retryInterval) return;
    43→  console.log("Starting background MongoDB reconnection (every 30s)...");
    44→  retryInterval = setInterval(async () => {
    45→    if (isConnected) {
    46→      if (retryInterval) { clearInterval(retryInterval); retryInterval = null; }
    47→      return;
    48→    }
    49→    console.log("Retrying MongoDB connection...");
    50→    const ok = await tryConnect(uri);
    51→    if (ok && retryInterval) { clearInterval(retryInterval); retryInterval = null; }
    52→  }, 30000);
    53→}
    54→
    55→export async function connectDB() {
    56→  if (isConnected) return;
    57→  if (!process.env.MONGODB_URI) {
    58→    throw new Error("MONGODB_URI must be set.");
    59→  }
    60→
    61→  const uri = process.env.MONGODB_URI!;
    62→
    63→  let connected = await tryConnect(uri);
    64→
    65→  if (!connected) {
    66→    console.log("Retrying MongoDB connection in 3 seconds...");
    67→    await new Promise(r => setTimeout(r, 3000));
    68→    connected = await tryConnect(uri);
    69→  }
    70→
    71→  if (!connected) {
    72→    console.log("Retrying MongoDB connection in 5 seconds...");
    73→    await new Promise(r => setTimeout(r, 5000));
    74→    connected = await tryConnect(uri);
    75→  }
    76→
    77→  if (!connected) {
    78→    console.warn("=== MongoDB unavailable. Will retry every 30s in background. Whitelist 0.0.0.0/0 in Atlas Network Access. ===");
    79→    startBackgroundRetry(uri);
    80→  }
    81→
    82→  mongoose.connection.on('disconnected', () => {
    83→    console.warn("MongoDB disconnected. Will retry...");
    84→    isConnected = false;
    85→    startBackgroundRetry(uri);
    86→  });
    87→
    88→  mongoose.connection.on('connected', async () => {
    89→    isConnected = true;
    90→    console.log("MongoDB reconnected successfully");
    91→    try {
    92→      const { seed } = await import("./seed");
    93→      await seed();
    94→    } catch (e: any) {
    95→      console.error("Post-reconnect seed failed:", e?.message);
    96→    }
    97→  });
    98→}
