     3→async function throwIfResNotOk(res: Response) {
     4→  if (!res.ok) {
     5→    const raw = (await res.text()) || res.statusText;
     6→    // If the server returned JSON like { message: "..." } or { error: "..." },
     7→    // surface only that human-readable text instead of the raw JSON blob.
     8→    let message = raw;
     9→    try {
    10→      const parsed = JSON.parse(raw);
    11→      message = parsed?.message || parsed?.error || raw;
    12→    } catch {
    13→      /* not JSON — keep raw text */
    14→    }
    15→    throw new Error(message);
    16→  }
    17→}
