    19→export async function apiRequest(
    20→  method: string,
    21→  url: string,
    22→  data?: unknown | undefined,
    23→): Promise<Response> {
    24→  const isFormData = data instanceof FormData;
    25→  const res = await fetch(url, {
    26→    method,
    27→    headers: isFormData ? {} : (data ? { "Content-Type": "application/json" } : {}),
    28→    body: isFormData ? data : (data ? JSON.stringify(data) : undefined),
    29→    credentials: "include",
    30→  });
    31→
    32→  await throwIfResNotOk(res);
    33→  return res;
    34→}
