    36→type UnauthorizedBehavior = "returnNull" | "throw";
    37→export const getQueryFn: <T>(options: {
    38→  on401: UnauthorizedBehavior;
    39→}) => QueryFunction<T> =
    40→  ({ on401: unauthorizedBehavior }) =>
    41→  async ({ queryKey }) => {
